class Solution(object):
    def maxMoves(self, kx, ky, positions):
        """
        :type kx: int
        :type ky: int
        :type positions: List[List[int]]
        :rtype: int
        """
        from collections import deque
        import sys

        # Knight moves
        moves = [(2,1), (2,-1), (-2,1), (-2,-1), (1,2), (1,-2), (-1,2), (-1,-2)]

        # Precompute knight distances using BFS
        def bfs_distance(start_x, start_y, end_x, end_y):
            """BFS to find minimum knight moves"""
            queue = deque([(start_x, start_y, 0)])
            visited = {(start_x, start_y)}

            while queue:
                x, y, dist = queue.popleft()

                if x == end_x and y == end_y:
                    return dist

                for dx, dy in moves:
                    nx, ny = x + dx, y + dy
                    if 0 <= nx < 50 and 0 <= ny < 50 and (nx, ny) not in visited:
                        visited.add((nx, ny))
                        queue.append((nx, ny, dist + 1))

            return float('inf')

        # Build distance matrix
        n = len(positions)
        # Include knight's starting position as position -1
        all_positions = [(kx, ky)] + positions
        dist_matrix = [[0] * (n + 1) for _ in range(n + 1)]

        for i in range(n + 1):
            for j in range(n + 1):
                if i != j:
                    dist_matrix[i][j] = bfs_distance(all_positions[i][0], all_positions[i][1],
                                                     all_positions[j][0], all_positions[j][1])

        # DP with bitmask: dp[mask][turn][pos] = max moves
        # mask: which pawns captured (bit i = pawn i captured)
        # turn: 0 for Alice, 1 for Bob
        # pos: current knight position (index in all_positions)

        memo = {}

        def dp(mask, turn, pos):
            """Return max moves starting from (mask, turn, pos)"""
            if mask == (1 << n) - 1:
                # All pawns captured
                return 0

            state = (mask, turn, pos)
            if state in memo:
                return memo[state]

            result = 0 if turn == 0 else float('inf')

            # Try capturing each uncaptured pawn
            for pawn_idx in range(n):
                if not (mask & (1 << pawn_idx)):
                    # Pawn pawn_idx hasn't been captured
                    moves_to_pawn = dist_matrix[pos][pawn_idx + 1]
                    new_mask = mask | (1 << pawn_idx)
                    remaining_moves = dp(new_mask, 1 - turn, pawn_idx + 1)

                    total_moves = moves_to_pawn + remaining_moves

                    if turn == 0:  # Alice's turn (maximize)
                        result = max(result, total_moves)
                    else:  # Bob's turn (minimize)
                        result = min(result, total_moves)

            memo[state] = result
            return result

        return dp(0, 0, 0)
